package main

import (
    "encoding/json"
    "net/http"
    "net/http/httptest"
    "reflect"
    "testing"
)

// HealthHandler returns a simple health check endpoint
func HealthHandler(w http.ResponseWriter, r *http.Request) {
    w.Header().Set("Content-Type", "application/json")
    response := map[string]string{"status": "ok"}
    json.NewEncoder(w).Encode(response)
}

// TestHealthHandler tests the HealthHandler function
func TestHealthHandler(t *testing.T) {
    tests := []struct {
        name           string
        method         string
        expectedStatus int
        expectedBody   string
        expectedHeader string
    }{
        {
            name:           "GET request returns OK status",
            method:         "GET",
            expectedStatus: http.StatusOK,
            expectedBody:   `{"status":"ok"}`,
            expectedHeader: "application/json",
        },
        {
            name:           "POST request returns OK status",
            method:         "POST",
            expectedStatus: http.StatusOK,
            expectedBody:   `{"status":"ok"}`,
            expectedHeader: "application/json",
        },
        {
            name:           "PUT request returns OK status",
            method:         "PUT",
            expectedStatus: http.StatusOK,
            expectedBody:   `{"status":"ok"}`,
            expectedHeader: "application/json",
        },
        {
            name:           "DELETE request returns OK status",
            method:         "DELETE",
            expectedStatus: http.StatusOK,
            expectedBody:   `{"status":"ok"}`,
            expectedHeader: "application/json",
        },
    }

    for _, tt := range tests {
        t.Run(tt.name, func(t *testing.T) {
            // Create a request
            req := httptest.NewRequest(tt.method, "/", nil)

            // Create a response recorder
            rr := httptest.NewRecorder()

            // Call the handler
            HealthHandler(rr, req)

            // Check status code
            if status := rr.Code; status != tt.expectedStatus {
                t.Errorf("HealthHandler() status = %v, want %v", status, tt.expectedStatus)
            }

            // Check content type header
            contentType := rr.Header().Get("Content-Type")
            if contentType != tt.expectedHeader {
                t.Errorf("HealthHandler() Content-Type = %v, want %v", contentType, tt.expectedHeader)
            }

            // Check response body (allowing for whitespace differences)
            if !reflect.DeepEqual(rr.Body.String(), tt.expectedBody) {
                t.Errorf("HealthHandler() body = %v, want %v", rr.Body.String(), tt.expectedBody)
            }
        })
    }
}

// Example usage
func main() {
    http.HandleFunc("/health", HealthHandler)
    http.ListenAndServe(":8080", nil)
}
