import (
    "errors"
    "fmt"
    "strings"
)

func ParseScopes(raw string) ([]string, error) {
    if raw == "" {
        return []string{}, nil
    }

    scopes := strings.Split(raw, ",")
    seen := make(map[string]bool)
    result := make([]string, 0)

    for _, scope := range scopes {
        trimmed := strings.TrimSpace(scope)
        if trimmed == "" {
            return nil, fmt.Errorf("empty scope found in input: %q", raw)
        }
        if !seen[trimmed] {
            seen[trimmed] = true
            result = append(result, trimmed)
        }
    }

    return result, nil
}
```

This implementation:

1. **Splits** the comma-separated string using `strings.Split`
2. **Trims spaces** from each scope using `strings.TrimSpace`
3. **Rejects empties** by checking if the trimmed string is empty and returning a wrapped error
4. **Dedups** by using a map to track seen scopes
5. **Fails closed** - returns an error immediately when an empty scope is encountered
6. **Handles edge cases** like empty input string gracefully

Example usage:
```go
scopes, err := ParseScopes("read, write, read,  publish ")
// Returns: []string{"read", "write", "publish"}, nil

scopes, err = ParseScopes("read,,write")
// Returns: nil, error with message about empty scope
```
